def attack_subjects(task_folder: str) -> list[str]:
    """The hackability attack subjects for a task (Axis 2).

    The mechanical attacks need no gold and are always available; the LLM
    `adversarial` agent is included only once it has been generated on disk
    (it is expensive, so it is built explicitly via `python -m eval.attacks
    --adversarial <task>`, never auto-built during a judge sweep)."""
    subs = list(attacks.attack_names(task_folder))
    if attacks.has_adversarial(task_folder):
        subs.append(attacks.ADVERSARIAL_NAME)
    return subs


def hack_subjects(task_folder: str) -> list[str]:
    """Cheap subjects whose passing a positive item counts as a leak: nulls + attacks."""
    return list(null_inputs.build_nulls(task_folder)) + attack_subjects(task_folder)


def resolve_subject(task_folder: str, subject: str) -> Bundle:
    """Map a subject string to a gradeable Bundle (deliverable + read-only references)."""
    if subject == "gold":
        if not has_gold(task_folder):
            raise SystemExit(f"{task_folder}: no gold deliverable released")
        return gold_bundle(task_folder)

    if subject.startswith("rollout:"):
        key = subject.split(":", 1)[1]
        d = rollout_dir(task_folder, key)
        if not d.exists() or not any(d.iterdir()):
            raise SystemExit(
                f"{task_folder}: no rollout for policy '{key}' "
                f"(run --mode rollout --policy-models {key} first)")
        return Bundle.with_references(subject, d, reference_dir(task_folder))

    if subject.startswith("preexisting:"):
        root = Path(subject.split(":", 1)[1]).expanduser()
        d = root / task_folder if (root / task_folder).is_dir() else root
        if not d.is_dir():
            raise SystemExit(f"{task_folder}: no preexisting outputs at {d}")
        return Bundle.with_references(subject, d, reference_dir(task_folder))

    # attack:<name> or a bare attack variant name (hackability subjects, Axis 2)
    name = subject.split(":", 1)[1] if subject.startswith("attack:") else subject

    # The LLM adversarial agent is generated out-of-band and resolved from disk
    # (never auto-built here, since it costs API calls).
    if name == attacks.ADVERSARIAL_NAME:
        if not attacks.has_adversarial(task_folder):
            raise SystemExit(
                f"{task_folder}: no adversarial deliverable generated yet "
                f"(run: python -m eval.attacks --adversarial {task_folder})")
        return Bundle.with_references(subject, attacks.adversarial_dir(task_folder),
                                      reference_dir(task_folder))

    atk = attacks.build_attacks(task_folder)
    if name in atk:
        return Bundle.with_references(subject, atk[name], reference_dir(task_folder))

    # otherwise treat it as a null variant name (blank / unedited_input / ...)
    nulls = null_inputs.build_nulls(task_folder)
    if subject not in nulls:
        raise SystemExit(
            f"{task_folder}: unknown subject '{subject}' (have: gold, "
            f"{', '.join(nulls) or 'no nulls'}, {', '.join(atk) or 'no attacks'}, "
            f"rollout:<key>, preexisting:<path>)")
    return null_bundle(task_folder, subject, nulls[subject])


